insert into job_listings (employer_id, title, company_name, location, remote_type, employment_type, salary_min, salary_max, currency, summary, description, responsibilities, requirements, benefits, interview_process, contact_email, status) values (null, 'Product Designer', 'Northstar Labs', 'New York, NY', 'Hybrid', 'Full-time', 125000, 155000, 'USD', 'Lead product design for a hiring analytics platform used by growing teams.', 'You will shape discovery, interaction design, and launch-ready product experiences with product and engineering partners.', 'Own end-to-end design for core workflows | Run user interviews and synthesize insights | Create polished prototypes for product reviews | Partner with engineers through delivery', '5+ years designing business software | Strong systems thinking and interaction design | Comfort working with ambiguous product problems | Portfolio with shipped product work', 'Health, dental, and vision coverage | Learning budget and conference travel | Flexible hybrid schedule | Equity package', 'Recruiter screen | Portfolio review | Collaborative product exercise | Final team conversation', 'hiring@northstar.example', 'published');
insert into job_listings (employer_id, title, company_name, location, remote_type, employment_type, salary_min, salary_max, currency, summary, description, responsibilities, requirements, benefits, interview_process, contact_email, status) values (null, 'Backend Engineer', 'Harbor Grid', 'Remote, US', 'Remote', 'Full-time', 140000, 180000, 'USD', 'Build reliable APIs and data services for a logistics planning product.', 'This role focuses on service architecture, database modeling, observability, and developer-friendly internal tooling.', 'Design and maintain TypeScript services | Model operational data and API contracts | Improve performance of high-volume workflows | Mentor teammates through reviews', 'Strong TypeScript and SQL experience | Experience with auth and data access patterns | Pragmatic testing habits | Clear written communication', 'Remote-first culture | Home office stipend | Quarterly team retreats | Generous parental leave', 'Hiring manager screen | Technical conversation | Paid work sample | Founder chat', 'jobs@harborgrid.example', 'published');
insert into job_listings (employer_id, title, company_name, location, remote_type, employment_type, salary_min, salary_max, currency, summary, description, responsibilities, requirements, benefits, interview_process, contact_email, status) values (null, 'Customer Success Lead', 'Bright Desk', 'Austin, TX', 'On-site', 'Full-time', 90000, 115000, 'USD', 'Help customers launch and expand a modern workplace operations tool.', 'You will own onboarding, retention plans, customer health reviews, and feedback loops with product.', 'Guide new customers through launch | Build success plans for strategic accounts | Identify expansion opportunities | Share product feedback with internal teams', '4+ years in customer success | Experience with B2B software | Confident presentation skills | Organized account planning', 'Commuter support | Wellness budget | Company lunch twice a week | Performance bonus', 'Recruiter screen | Customer scenario discussion | Panel interview', 'careers@brightdesk.example', 'published');
